void set_batch(batch::CommandBatch* batch) {
    g_batch = batch;
    SPDLOG_INFO("OmniGPU batch set ({} commands threshold)",
                batch ? batch->command_count() : 0);
}

batch::CommandBatch* get_batch() {
    return g_batch;
}

void shutdown_hooks() {
    if (!g_initialized) return;
    g_batch = nullptr;
    get_original_fns().clear();
    g_initialized = false;
#ifdef _WIN32
    if (s_real_vulkan) {
        ::FreeLibrary(static_cast<HMODULE>(s_real_vulkan));
        s_real_vulkan = nullptr;
    }
#endif
    SPDLOG_INFO("OmniGPU intercept shut down");
}

